16	
17	`include "defines.svh"
18	
19	import defines::*;
20	
21	//
22	// L2 Bus Interface
23	// Receives L2 cache misses and writeback requests from the L2 pipeline and
24	// drives system memory interface to fulfill them. When fills complete,
25	// this reissues them to the L2 pipeline via the arbiter.
26	//
27	// If a load miss is already pending for a line, this set a flag on the FIFO
28	// entry that will skip the load. It will, however, still reissue it to the
29	// L2 pipeline.
30	//
31	// The interface to system memory is the AMBA AXI interface.
32	// http://www.arm.com/products/system-ip/amba-specifications.php
33	//
34	// I've tried to keep all bus logic consolidated in this module to make it
35	// easier to swap this out for other bus implementations (eg Wishbone).
36	//
37	// Todo: This should issue the address for the next bus transaction before it
38	// has finished the previous data transfer to improve utilization, especially
39	// in systems with larger memory latency.
40	//
41	
42	module l2_axi_bus_interface(
43	    input                                  clk,
44	    input                                  reset,
45	
46	    axi4_interface.master                  axi_bus,
47	
48	    // To l2_cache_arb_stage
49	    output logic                           l2bi_request_valid,
50	    output l2req_packet_t                  l2bi_request,
51	    output cache_line_data_t               l2bi_data_from_memory,
52	    output logic                           l2bi_stall,
53	    output logic                           l2bi_collided_miss,
54	
55	    // From l2_cache_read_stage
56	    input                                  l2r_needs_writeback,
57	    input l2_tag_t                         l2r_writeback_tag,
58	    input cache_line_data_t                l2r_data,
59	    input                                  l2r_l2_fill,
60	    input                                  l2r_restarted_flush,
61	    input                                  l2r_cache_hit,
62	    input                                  l2r_request_valid,
63	    input l2req_packet_t                   l2r_request,
64	
65	    // To performance_counters
66	    output logic                           l2bi_perf_l2_writeback);
67	
68	    typedef enum {
69	        STATE_IDLE,
70	        STATE_WRITE_ISSUE_ADDRESS,
71	        STATE_WRITE_TRANSFER,
72	        STATE_READ_ISSUE_ADDRESS,
73	        STATE_READ_TRANSFER,
74	        STATE_READ_COMPLETE
75	    } bus_interface_state_t;
76	
77	    typedef struct packed {
78	        cache_line_index_t address;
79	        cache_line_data_t data;
80	        logic flush;
81	        core_id_t core;
82	        l1_miss_entry_idx_t id;
83	    } writeback_fifo_entry_t;
84	
85	    localparam FIFO_SIZE = 8;
86	
87	    // This is the number of stages before this one in the pipeline. Assert the
88	    // signal to stop accepting new packets this number of cycles early so
89	    // requests that are already in the L2 pipeline don't overrun the FIFOs.
90	    localparam L2REQ_LATENCY = 4;
91	    localparam BURST_BEATS = CACHE_LINE_BITS / `AXI_DATA_WIDTH;
92	    localparam BURST_OFFSET_WIDTH = $clog2(BURST_BEATS);
93	
94	    l2_addr_t miss_addr;
95	    cache_line_index_t writeback_address;
96	    logic enqueue_writeback_request;
97	    logic enqueue_fill_request;
98	    logic duplicate_request;
99	    cache_line_data_t writeback_data;
100	    logic[`AXI_DATA_WIDTH - 1:0] writeback_lanes[BURST_BEATS];
101	    logic writeback_fifo_empty;
102	    logic fill_queue_empty;
103	    logic fill_request_pending;
104	    logic writeback_pending;
105	    logic writeback_complete;
106	    logic writeback_fifo_almost_full;
107	    logic fill_queue_almost_full;
108	    bus_interface_state_t state_ff;
109	    bus_interface_state_t state_nxt;
110	    logic[BURST_OFFSET_WIDTH - 1:0] burst_offset_ff;
111	    logic[BURST_OFFSET_WIDTH - 1:0] burst_offset_nxt;
112	    logic[`AXI_DATA_WIDTH - 1:0] fill_buffer[0:BURST_BEATS - 1];
113	    logic restart_flush_request;
114	    logic fill_dequeue_en;
115	    l2req_packet_t lmq_out_request;
116	    writeback_fifo_entry_t writeback_fifo_in;
117	    writeback_fifo_entry_t writeback_fifo_out;
118	
119	    assign miss_addr = l2r_request.address;
120	    assign enqueue_writeback_request = l2r_request_valid && l2r_needs_writeback
121	        && ((l2r_request.packet_type == L2REQ_FLUSH && l2r_cache_hit && !l2r_restarted_flush)
122	        || l2r_l2_fill);
123	    assign enqueue_fill_request = l2r_request_valid && !l2r_cache_hit && !l2r_l2_fill
124	        && (l2r_request.packet_type == L2REQ_LOAD
125	        || l2r_request.packet_type == L2REQ_STORE
126	        || l2r_request.packet_type == L2REQ_LOAD_SYNC
127	        || l2r_request.packet_type == L2REQ_STORE_SYNC);
128	    assign writeback_pending = !writeback_fifo_empty;
129	    assign fill_request_pending = !fill_queue_empty;
130	
131	    l2_cache_pending_miss_cam l2_cache_pending_miss_cam(
132	        .request_valid(l2r_request_valid),
133	        .request_addr({miss_addr.tag, miss_addr.set_idx}),
134	        .*);
135	
136	    assign writeback_fifo_in.address = {l2r_writeback_tag, miss_addr.set_idx}; // Old address
137	    assign writeback_fifo_in.data = l2r_data; // Old line to writeback
138	    assign writeback_fifo_in.flush = l2r_request.packet_type == L2REQ_FLUSH;
139	    assign writeback_fifo_in.core = l2r_request.core;
140	    assign writeback_fifo_in.id = l2r_request.id;
141	
142	    sync_fifo #(
143	        .WIDTH($bits(writeback_fifo_entry_t)),
144	        .SIZE(FIFO_SIZE),
145	        .ALMOST_FULL_THRESHOLD(FIFO_SIZE - L2REQ_LATENCY)
146	    ) pending_writeback_fifo(
147	        .clk(clk),
148	        .reset(reset),
149	        .flush_en(1'b0),
150	        .almost_full(writeback_fifo_almost_full),
151	        .enqueue_en(enqueue_writeback_request),
152	        .enqueue_value(writeback_fifo_in),
153	        .almost_empty(),
154	        .empty(writeback_fifo_empty),
155	        .dequeue_en(writeback_complete),
156	        .dequeue_value(writeback_fifo_out),
157	        .full(/* ignore */));
158	
159	    assign writeback_address = writeback_fifo_out.address;
160	    assign writeback_data = writeback_fifo_out.data;
161	
162	    sync_fifo #(
163	        .WIDTH($bits(l2req_packet_t) + 1),
164	        .SIZE(FIFO_SIZE),
165	        .ALMOST_FULL_THRESHOLD(FIFO_SIZE - L2REQ_LATENCY)
166	    ) pending_fill_fifo(
167	        .clk(clk),
168	        .reset(reset),
169	        .flush_en(1'b0),
170	        .almost_full(fill_queue_almost_full),
171	        .enqueue_en(enqueue_fill_request),
172	        .enqueue_value({duplicate_request, l2r_request}),
173	        .empty(fill_queue_empty),
174	        .almost_empty(),
175	        .dequeue_en(fill_dequeue_en),
176	        .dequeue_value({l2bi_collided_miss, lmq_out_request}),
177	        .full(/* ignore */));
178	
179	    // Stop accepting new L2 packets until space is available in the queues
180	    assign l2bi_stall = fill_queue_almost_full || writeback_fifo_almost_full;
181	
182	    // AMBA AXI and ACE Protocol Specification, rev E, A3.4.1:
183	    // length field is is burst length - 1
184	    assign axi_bus.m_awlen = 8'(BURST_BEATS - 1);
185	    assign axi_bus.m_arlen = 8'(BURST_BEATS - 1);
186	    assign axi_bus.m_bready = 1'b1;
187	    assign axi_bus.m_awprot = 3'b000;
188	    assign axi_bus.m_arprot = 3'b000;
189	    assign axi_bus.m_aclk = clk;
190	    assign axi_bus.m_aresetn = !reset;
191	
192	    // Flatten array
193	    genvar fill_buffer_idx;
194	    generate
195	        for (fill_buffer_idx = 0; fill_buffer_idx < BURST_BEATS; fill_buffer_idx++)
196	        begin : mem_lane_gen
197	            assign l2bi_data_from_memory[fill_buffer_idx * `AXI_DATA_WIDTH+:`AXI_DATA_WIDTH]
198	                = fill_buffer[BURST_BEATS - fill_buffer_idx - 1];
199	        end
200	    endgenerate
201	
202	    logic wait_axi_write_response;
203	
204	    // Bus state machine
205	    always_comb
206	    begin
207	        state_nxt = state_ff;
208	        fill_dequeue_en = 0;
209	        burst_offset_nxt = burst_offset_ff;
210	        writeback_complete = 0;
211	        restart_flush_request = 0;
212	
213	        unique case (state_ff)
214	            STATE_IDLE:
215	            begin
216	                // Writebacks take precendence over loads to avoid a race condition
217	                // where this loads stale data. Since loads can also enqueue writebacks,
218	                // it ensures this doesn't overrun the write FIFO.
219	                if (writeback_pending)
220	                begin
221	                    if (!wait_axi_write_response)
222	                        state_nxt = STATE_WRITE_ISSUE_ADDRESS;
223	                end
224	                else if (fill_request_pending)
225	                begin
226	                    if (l2bi_collided_miss
227	                        || (lmq_out_request.store_mask == {CACHE_LINE_BYTES{1'b1}}
228	                        && lmq_out_request.packet_type == L2REQ_STORE))
229	                    begin
230	                        // Skip the read and restart the request immediately if:
231	                        // 1. If there is already a pending L2 miss for this cache
232	                        //    line. Some other request has filled it, so
233	                        //    don't need to do anything but (try to) pick up the
234	                        //    result. That could result in another miss in some
235	                        //    cases, in which case must make another pass through
236	                        //    here.
237	                        // 2. It is a store that replaces the entire line.
238	                        //    Let this flow through the read miss queue instead
239	                        //    of handling it immediately in the pipeline
240	                        //    because it must go through the pending miss unit
241	                        //    to reconcile any other misses that may be in progress.
242	                        state_nxt = STATE_READ_COMPLETE;
243	                    end
244	                    else
245	                        state_nxt = STATE_READ_ISSUE_ADDRESS;
246	                end
247	            end
248	
249	            STATE_WRITE_ISSUE_ADDRESS:
250	            begin
251	                burst_offset_nxt = 0;
252	                if (axi_bus.s_awready)
253	                    state_nxt = STATE_WRITE_TRANSFER;
254	            end
255	
256	            STATE_WRITE_TRANSFER:
257	            begin
258	                if (axi_bus.s_wready)
259	                begin
260	                    if (burst_offset_ff == {BURST_OFFSET_WIDTH{1'b1}})
261	                    begin
262	                        writeback_complete = 1;
263	                        restart_flush_request = writeback_fifo_out.flush;
264	                        state_nxt = STATE_IDLE;
265	                    end
266	
267	                    burst_offset_nxt = burst_offset_ff + BURST_OFFSET_WIDTH'(1);
268	                end
269	            end
270	
271	            STATE_READ_ISSUE_ADDRESS:
272	            begin
273	                burst_offset_nxt = 0;
274	                if (axi_bus.s_arready)
275	                    state_nxt = STATE_READ_TRANSFER;
276	            end
277	
278	            STATE_READ_TRANSFER:
279	            begin
280	                if (axi_bus.s_rvalid)
281	                begin
282	                    if (burst_offset_ff == {BURST_OFFSET_WIDTH{1'b1}})
283	                        state_nxt = STATE_READ_COMPLETE;
284	
285	                    burst_offset_nxt = burst_offset_ff + BURST_OFFSET_WIDTH'(1);
286	                end
287	            end
288	
289	            STATE_READ_COMPLETE:
290	            begin
291	                // Push the response back into the L2 pipeline
292	                state_nxt = STATE_IDLE;
293	                fill_dequeue_en = 1'b1;
294	            end
295	        endcase
296	    end
297	
298	    genvar writeback_lane;
299	    generate
300	        for (writeback_lane = 0; writeback_lane < BURST_BEATS; writeback_lane++)
301	        begin : writeback_lane_gen
302	            assign writeback_lanes[writeback_lane] = writeback_data[
303	                writeback_lane * `AXI_DATA_WIDTH+:`AXI_DATA_WIDTH];
304	        end
305	    endgenerate
306	
307	    always_comb
308	    begin
309	        l2bi_request = lmq_out_request;
310	        if (restart_flush_request)
311	        begin
312	            // For this request, the other fields in the request packet are ignored.
313	            // To avoid creating a mux for them, we just leave them assigned to
314	            // the load_reuqest fields.
315	            l2bi_request_valid = 1'b1;
316	            l2bi_request.packet_type = L2REQ_FLUSH;
317	            l2bi_request.core = writeback_fifo_out.core;
318	            l2bi_request.id = writeback_fifo_out.id;
319	            l2bi_request.cache_type = CT_DCACHE;
320	        end
321	        else
322	            l2bi_request_valid = fill_dequeue_en;
323	    end
324	
325	    always_ff @(posedge clk, posedge reset)
326	    begin : update
327	        if (reset)
328	        begin
329	            state_ff <= STATE_IDLE;
330	            /*AUTORESET*/
331	            // Beginning of autoreset for uninitialized flops
332	            axi_bus.m_arvalid <= '0;
333	            axi_bus.m_awvalid <= '0;
334	            axi_bus.m_rready <= '0;
335	            axi_bus.m_wlast <= '0;
336	            axi_bus.m_wvalid <= '0;
337	            burst_offset_ff <= '0;
338	            l2bi_perf_l2_writeback <= '0;
339	            wait_axi_write_response <= '0;
340	            // End of automatics
341	        end
342	        else
343	        begin
344	            state_ff <= state_nxt;
345	            burst_offset_ff <= burst_offset_nxt;
346	
347	            // Write response state machine
348	            if (state_ff == STATE_WRITE_ISSUE_ADDRESS)
349	                wait_axi_write_response <= 1;
350	            else if (axi_bus.s_bvalid)
351	                wait_axi_write_response <= 0;
352	
353	            // Register AXI output signals
354	            axi_bus.m_arvalid <= state_nxt == STATE_READ_ISSUE_ADDRESS;
355	            axi_bus.m_rready <= state_nxt == STATE_READ_TRANSFER;
356	            axi_bus.m_awvalid <= state_nxt == STATE_WRITE_ISSUE_ADDRESS;
357	            axi_bus.m_wvalid <= state_nxt == STATE_WRITE_TRANSFER;
358	            axi_bus.m_wlast <= state_nxt == STATE_WRITE_TRANSFER
359	                && burst_offset_nxt == BURST_OFFSET_WIDTH'(BURST_BEATS - 1);
360	            l2bi_perf_l2_writeback <= enqueue_writeback_request
361	                && !writeback_fifo_almost_full;
362	        end
363	    end
364	
365	    always_ff @(posedge clk)
366	    begin
367	        if (state_ff == STATE_READ_TRANSFER && axi_bus.s_rvalid)
368	            fill_buffer[burst_offset_ff] <= axi_bus.s_rdata;
369	
370	        axi_bus.m_araddr <= {l2bi_request.address, {CACHE_LINE_OFFSET_WIDTH{1'b0}}};
371	        axi_bus.m_awaddr <= {writeback_address, {CACHE_LINE_OFFSET_WIDTH{1'b0}}};
372	        axi_bus.m_wdata <= writeback_lanes[~burst_offset_nxt];
373	    end
374	endmodule
