"""Run unit tests against individual verilog modules.

This compiles each one separately, then looks for the string 'PASS'
in the output.
"""

import os
import subprocess
import sys

sys.path.insert(0, '..')
import test_harness

DRIVER_PATH = os.path.join(test_harness.WORK_DIR, 'driver.cpp')
DRIVER_SRC = """
#include <iostream>
#include <stdlib.h>
#include "V$MODULE$.h"
#include "verilated.h"
#include "verilated_vpi.h"
#if VM_TRACE
#include <verilated_vcd_c.h>
#endif
using namespace std;

namespace
{
vluint64_t currentTime = 0;
}

// Called whenever the $time variable is accessed.
double sc_time_stamp()
{
    return currentTime;
}

int main(int argc, char **argv, char **env)
{
    Verilated::commandArgs(argc, argv);
    Verilated::debug(0);

    V$MODULE$ *testbench = new V$MODULE$;

    return

if test_args.target:
    targets_to_run = test_args.target
else:
    targets_to_run = DEFAULT_TARGETS

# Filter based on names and targets
if test_args.names:
    tests_to_run = []
    for requested in test_args.names:
        for func, param, targets in registered_tests:
            if param == requested:
                tests_to_run += [(func, param, targets)]
                break
        else:
            print('Unknown test ' + requested)
            sys.exit(1)
else:
    tests_to_run = registered_tests

test_run_count = 0
test_pass_count = 0
failing_tests = []
for func, param, targets in tests_to_run:
    for target in targets:
        if target not in targets_to_run:
            continue

        label = '{}({})'.format(param, target)
        print(label + (' ' * (OUTPUT_ALIGN - len(label))), end='')
        try:
            # Clean out working directory and re-create
            shutil.rmtree(path=WORK_DIR, ignore_errors=True)
            os.makedirs(WORK_DIR)

            test_run_count += 1
            sys.stdout.flush()
            with TerminalStateRestorer():
